input.command:
cd /tmp && cat > /tmp/kptest.nix <<'EOF'
let
  lib = (import <nixpkgs> {}).lib;
  eval = modules: (lib.evalModules {
    modules = modules ++ [
      ({ lib, ... }: { options.boot.kernelParams = lib.mkOption { type = lib.types.listOf lib.types.str; default = []; }; })
    ];
  }).config.boot.kernelParams;
in {
  # host sets plain, module uses mkDefault -> does panic=20 survive?
  withMkDefault = eval [
    ({ ... }: { boot.kernelParams = [ "usbcore.autosuspend=-1" ]; })       # host, priority 100
    ({ lib, ... }: { boot.kernelParams = lib.mkDefault [ "panic=20" ]; })   # module, priority 1000
  ];
  # both plain -> concatenation
  bothPlain = eval [
    ({ ... }: { boot.kernelParams = [ "usbcore.autosuspend=-1" ]; })
    ({ ... }: { boot.kernelParams = [ "panic=20" ]; })
  ];
}
EOF
nix eval --impure --expr "import /tmp/kptest.nix" 2>&1 | head -20 || nix-instantiate --eval --strict /tmp/kptest.nix 2>&1 | head -20

